module top_module(sck, rst, add1, init_val, count);parameter SIZE = 13;

   input sck;
   input rst;
   input add1;
   input [SIZE-1:0] init_val;   

   output reg [SIZE-1:0] count = 0;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge sck or posedge dbg_halt)
     if(rst)
       count = init_val;
     else
       begin
	  if(add1)
	    count = count + 1'b1;
	  else
	    count = count;
       end

endmodule
